// Locates and reads the OpenAPI spec at <repo>/docs/api.json.
//
// docs/api.json is generated by `clojure -M:ee:doc api-documentation` and is
// gitignored — it only exists after `./bin/mage docs-generate --api` (or a full
// `bun run docs:build`). So we read it at build time instead of `import`ing it:
// a static `import ... from "../../docs/api.json"` would make Vite fail the
// whole dev server / build on a fresh checkout where the file isn't present.
//
// We resolve the path relative to `process.cwd()` (which is always `docs-build/`
// when running `astro dev` / `astro build`, same as the content-collection glob
// in src/content.config.ts) rather than `import.meta.url`, which doesn't survive
// Vite bundling — see the note in src/lib/nav.ts.
import fs from "node:fs";
import path from "node:path";

export const API_JSON_PATH = path.resolve(process.cwd(), "../docs/api.json");

// Minimal valid OpenAPI document — keeps api.json.ts serving something parseable
// when the real spec is absent (api.astro renders a "not generated" notice).
export const STUB_API_SPEC = {
  openapi: "3.1.0",
  info: { title: "Metabase API — not generated", version: "0" },
  paths: {},
} as const;

export function hasApiSpec(): boolean {
  return fs.existsSync(API_JSON_PATH);
}

export function readApiSpec(): unknown {
  try {
    return JSON.parse(fs.readFileSync(API_JSON_PATH, "utf8"));
  } catch {
    return STUB_API_SPEC;
  }
}
